import{c as o,a0 as t,S as n,j as l,o as s,aA as r,g as e,n as u,m as d}from"./chunks/framework.CbmBAXQm.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"about/description.md","filePath":"about/description.md","lastUpdated":1782577383000}'),h={name:"about/description.md"};function m(c,i,g,p,b,f){const a=t("Collapsible");return n(),l("div",null,[s(a,{title:"Work in progress"},{default:r(()=>[...i[0]||(i[0]=[e("p",null,"to understand context, we must look at the environment; denpa-song went through various periods & is generally strongly associated with entertainment & japanese culture",-1),e("ul",null,[e("li",null,[u("the following can be said in summary: "),e("ul",null,[e("li",null,"1960s-1980s [ RISE OF IDOL KAYO | RISE OF DOUJIN | BISHOUJO BOOM ]"),e("li",null,"v"),e("li",null,"1990s [ RISE OF J-POP | VN BOOM | AKIHABARA OTAKU TAKEOVER ]"),e("li",null,"v"),e("li",null,"2000s [ BBS CULTURE (2ch) | NICO NICO DOUGA (UTAITE) | VOCALOID ]"),e("li",null,"v"),e("li",null,'2010s-2020s [ DENPA EXPOSURE OVERSEAS (4chan /jp/) | RHYTHM GAMES | VTUBER INDUSTRY | "CUTECORE" ]')])])],-1),e("p",null,"please remember the folloqing quote:",-1),e("p",null,`"in japan the mainstream culture is always what's been adopted from foreign cultures. subculture is where real japanese culture lies."`,-1)])]),_:1}),i[1]||(i[1]=d("<hr><p>1940s-1950s:</p><ul><li>post-war akahon manga aimed at children, paving the way for modern manga to come thanks to creators like Osamu Tezuka who is most notably known for his works &#39;New Treasure Island&#39; and later &#39;Astro Boy&#39;; marking the boom of the manga industry</li><li>american occupation had a huge impact on the cartooning industry at the time</li></ul><hr><p>1960s:</p><ul><li>1960s marked protests by university students and lower-class migrant workers in urban areas against Vietnam War and American imperialism (youth radicalism)</li><li>the meeting &quot;Animation Association of Three&quot; (アニメーション三人の会) was founded by manga artist and filmmaker Kuri Youji alongside Yanagihara Ryouhei &amp; Manabe Hiroshi; paving the way for japanese animation to come in the 70s</li><li>1960s marked the introduction of the mahou shoujo trope through the manga &#39;The Secret of Akko-chan&#39; written &amp; illustrated by Fujio Akatsuka in July 1962 alongside &#39;Sally the Witch&#39; written and illustrated by Mitsuteru Yokoyama in July 1966</li><li>university campus riots of 1968 to 1970</li><li>initial television anime boom in the 1960s</li></ul><hr><p>1970s:</p><ul><li>cheap and portable offset printing and photocopying facilities rapidly became available to the public <ul><li>paved the way for doujinka and their doujinshi</li></ul></li><li>growth of the commercial manga industry slowly in the 1970s, and then rapidly during the 1980s</li><li>microcomputer boom had already established itself in the 70s</li><li>mass consumerism of 1970s including televised song contests gave spotlight to idol culture and thus the idol boom</li><li>large publishing companies ceased to systematically produce radical and stylistically innovatory manga series around 1972 because they no longer matched sufficiently closely the changed interests of their mass audiences</li><li>Space Battleship Yamato started airing in 1974; this marks a period where sci-fi, the space race &amp; technological innovation were thriving</li><li>the &#39;Japanese Manga Convention&#39; (日本漫画大会) was first held on 1972 however tensions arose in 1974 during its third iteration after it received criticism regarding the guidelines &amp; management of the convention and it would eventually fade away in 1981 at its 10th and last iteration; the famous Comiket was formed in response to these tensions</li><li>1975 marked the establishment of the &#39;Manga Research Club&#39; (漫画研究会) in numerous universities <ul><li>this marked a shift where otaku began to prioritize introspection and self-discovery over political engagement; an antithesis to the political activism</li></ul></li><li>in the mid 1970s a group of female artists producing high quality manga emerged called the &#39;1949 Group&#39; or also the &#39;Year 24 Group&#39; (&#39;nijuyon-nen gumi&#39; / &#39;24年組&#39;) <ul><li>contributed heavily to the development of shoujo manga</li></ul></li><li>a group of young manga critics (Aniwa Jun, Harada Teruo and Yonezawa Yoshihiro) founded Comic Market (Comiket) in late 1975, giving birth to doujin culture; significant rise in the 1980s; early on it was largely dominated by women <ul><li>first instance held 32 amateur manga circles and 600 individuals</li><li>marking the hiragana otaku, the first otaku generation</li><li>the home video revolution arrived, with the VHS being introduced in 1976 and being dominant in the 80s as videotape technology became affordable for home use <ul><li>making it possible to to record, play back, study and share anime which became cultivaed by the first otaku at the time</li></ul></li><li>Rumiko Takahashi&#39;s professional career began with Urusei Yatsura in 1978</li><li>Mobile Suit Gundam began airing in 1979, marking the birth of the gundam mecha series</li></ul></li><li>birth rates continued to decline</li></ul><hr><p>1980s:</p><ul><li>japanese bubble economy emerged in 1980s</li><li>lolicon/bishoujo boom took place in the early 80s</li><li>the anime market was booming as studios had funding; miyazaki hayao would co-found studio ghibli in 1985</li><li>parody series became popular among doujin audience in the early 80s</li><li>Nanako SOS by Hideo Azuma starting in April 1980</li><li>moe elements gradually appeared as early as the 80s but would start to peak in the 2000s; <ul><li>followed by a smaller lolicon boom</li></ul></li><li>rise of japanese BBS (bulletin board system) in the early 1980s</li><li>PC-8800 series (&quot;Lolita: Yakyuuken&quot;, &quot;100円ディスク&quot;, ..)</li><li>Fujitsu FM-7</li><li>the opening animation to Daicon III was released in 1981</li><li>amassing a large enough quantity of software provided a hedge against risk through economies of scale <ul><li>selling hardware while simultaneously purchasing used software from enthusiasts and reselling it under their own store brands</li><li>rise to the business model characteristic of early computer shops</li></ul></li><li>bishoujo magazine Lemon People starting in February 1982 (- Magical Princess Minky Momo (anime series, 1982)) (- Creamy Mami, the Magic Angel (anime series, 1983))</li><li>Fukagawa Street Murders (深川通り魔殺人事件) had occured</li><li>Musical Instrument Digital Interface (MIDI) protocol introduced in 1983</li><li>Otaku was coined during bishoujo magazine Manga Burikko in 1983 by Akio Nakamori</li><li>the opening animation to Daicon IV was released in 1983</li><li>Comitia was founded in 1984</li><li>cosplays became widespread in the 1980s and onwards</li><li>idols (like Lemon Angel, formed 1987) provided music for Cream Lemon &amp; OVA adaptations of bishoujo manga like Outlanders (1986)</li><li>three of the biggest and most costly animated movies arrived toward the end of the 1980s: &#39;Wings of Honneamise&#39; by Gainax in 1987, &#39;My Neighbor Totoro&#39; by Hayao Miyazaki &amp; &#39;Akira&#39; by Otomo Katsuhiro; this would also mark a period where the anime market would implode and go into recession; studios turned towards the production of computer games, figures &amp; idol singers</li><li>NES games (Nintendo’s Famicom); Idol Hakkenden (1989)</li><li>chiptune soundtracks (Idol Hakkenden, 1989) <ul><li>could not contain both graphic data and recorded sound due to storage limitations</li></ul></li><li>Tsutomu Miyazaki incident had occured, causing a huge moral panic <ul><li>marking the katakana otaku from here on out</li></ul></li><li>until the late 1980s, approximately 80% of dojinshi artists attending Comic Market were female <ul><li>universities began to boast not only manga clubs, but also, girls&#39; manga clubs for men</li></ul></li><li>Osamu Tezuka passed away in 1989</li></ul><hr><p>1990s:</p><ul><li>lost decades kicking in starting in the early 1990s as the asset price bubble bursted</li><li>household electronics stores were going bankrupt, and stores began to shift away from consumer electronics to personal computers alongside relocating from akihabara to the suburbs or other chain stores such as &#39;Yodobashi Camera&#39;, &#39;Sakuraya&#39; &amp; &#39;Bic Camera&#39; around Shinjuku, Shibuya &amp; Ikebukuro <ul><li>therefore mainstream culture would fade away from this town and otaku-loathing women would gradually shift away too; families would stop coming; specialists &amp; hobbyists remained; usually young males interested in computers, anime &amp; games</li></ul></li><li>Moore&#39;s Law started showing its true colors in the early 1990s; key ingredients for the eroge/visual-novel boom established</li><li>katakana otaku (オタク) emerged roughly after tsutumo miyazaki incident that replaced the hiragana otaku (おたく)</li><li>anime figurines began to take off in the 90s though anime-related figures such as garage kits in the 80s and shokugan in the 60s existed prior to bishoujo figurines</li><li>during 1991 police arrested the managers of five specialist manga book shops where unpublished or amateur manga was available for sale <ul><li>amateur manga artists were subjected to repeated investigations and harassment throughout the rest of the year</li></ul></li><li>AnimeCon &#39;91 is the first anime event to break the 1000-person mark in the US, marking the beginnings of mass otaku &amp; convention culture in the US; this convention was the predecessor to the famous &#39;Anime Expo&#39;</li><li>Anime Expo was founded in 1992</li><li>in 1993, guidance about the appropriate contents of dojinshi were distributed at Comic Market for the first time <ul><li>prohibiting the sale of sexually explicit published materials to minors of 18 years and under despite the fact that a large proportion of amateur manga is produced and sold by minors</li></ul></li><li>since 1993, 16000 separate doujin circles participated in every instance of comiket, with over 30000 applications in total (Harumi Trade Centre)</li><li>Tokyo subway sarin attack by the japanese cult &#39;Aum Shinrikyo&#39; in march 1995</li><li>nerdcore techno emerged in the mid 1990s; precursor to j-core music</li><li>1995&#39;s Tokimeki Memorial &amp; 1997&#39;s To Heart are successful examples &amp; paved the way for bishoujo games</li><li>PC-98 games (NEC’s PC-9800 series); visual novels were being produced (more games: &quot;Sostugyou ~Graduation~&quot;) <ul><li>Shizuku (Leaf) <ul><li>followed by &quot;big three&quot; denpa games (3大電波ゲーム): Tsui no Sora, Sayonara Wo Oshiete, Jisatsu no Tame no 101 no Houhou <ul><li>followed by Saya no Uta, Chaos;Head, Subarashiki Hibi, Kimi to Kanojo to Kanojo no Koi</li><li>(CROSS†CHANNEL, SSSS.Gridman)</li><li>popular denpa vn authors SCA-DI &amp; Tanaka Romeo</li></ul></li></ul></li></ul></li><li>rise of moe songs (akiba-idol, theme songs, eroge songs) in the mid 1990s (inspired by idol culture, mahou shoujo genre, bishoujo &amp; internet technology)</li><li>Neon Genesis Evangelion had aired starting in 1995, inspiring this period nicknamed by &#39;Evangelion Boom&#39; &amp; kicking off the anime bubble <ul><li>inspiring &quot;Serial Experiments Lain&quot;, &quot;Paranoia Agent&quot;, &quot;Perfect Blue&quot;</li><li>starting the real akiba transformation, causing shops selling figurines and doujinshi to boom</li><li>evangelion eventually ran out of funds towards the end of the 26-episode run, with the last two episodes being filled by &quot;The End of Evangelion&quot; with the last two episodes serving as an alternate ending</li></ul></li><li>anime became increasingly popular overseas in the mid-late 90s, eventually leading to the government taking notice &amp; rolling out the &#39;Cool Japan&#39; initiative in the upcoming decade</li><li>Haruko Momoi, one of the earliest akiba-idols, recorded the song &#39;GURA GURA&#39; in the center of akihabara in 1997</li><li>figure maker Kaiyodo moved from Shibuya to Akihabara, and other otaku-oriented stores followed</li><li>Beatmania released in December 1997, sparking the boom of music games in 1998</li><li>Dance Dance Revolution released in in 1998, finding huge success outside of japan as well</li><li>Windows PC (x86, Windows 95/98/2000) <ul><li>introducing bishoujo games</li></ul></li><li>a bombing incident occured at Comiket 54 in 1998 in response to the hatred for otaku</li><li>mega-BBS 2channel (2ch) launched 30 May 1999</li></ul><hr><p>2000s:</p><ul><li>early 2000s saw the rise of maid cafés across akihabara and elsewhere</li><li>OS-tan as a branch of moe anthropomorphism in the 2000s to accommodate depiction operating systems as moe characters</li><li>Ukagaka emerged alongside OS-tan</li><li>&quot;Otaku: Japan&#39;s Database Animals&quot; published in 2001</li><li>StepMania was initially released in 2001 as an open source clone of Dance Dance Revolution</li><li>Guidebook of funny dempa song released in the jp community in 2003, making denpa song relevant across jp &amp; western BBSes including 2ch, world2ch, 4-ch and more</li><li>vocaloid was released in January 15, 2004</li><li>Densha Otoko published October 22, 2004, alongside its TV drama in 2005</li><li>lolicore emerged in the mid 2000s which is more or less the western equivalent &amp; extension of nerdcore techno that incorporates western bulletin board culture, moe/lolicon imagery, weeaboo culture mimicking otaku influence overseas &amp; offensive language intended to gatekeep itself</li><li>Denpa Otoko (電波男) (in responde to Densha Otoko) published in May 2005</li><li>it is said that Akihabara truly peaked in the mid 2000s</li><li>nico nico douga was founded in 2006</li><li>osu! was released on September 2007</li><li>Anime Festival Asia first emerged in 2008, bringing southeast asia together to celebrate japanese pop culture in singapore; it has been a regular fixture ever since</li><li>utaite have gradually popped up in the late 2000s in relation to nico nico douga</li><li>Akihabara incident in June 8, 2008 which was caused by Kato Tomohiro who rented a truck and drove into &amp; stabbed a crowd of visitors walking on Chuo-dori street in Akihabara <ul><li>resulting in Chuo-dori being opened to traffic on sundays which would kill public activity as the spot served as a gathering for otaku</li><li>since this event, people would be arrested for posting threatening notices on BBS sites such as 2ch <ul><li>a similar threat, moreso a bomb threat, was announced on 2ch for the summer Comiket in 2008 though the culprit was arrested upon entry</li></ul></li></ul></li></ul><hr><p>2010s:</p><ul><li>&#39;Cool Japan&#39; initiative was launched in the 2010s to turn the spot into a tourist destination for pop culture but the initiative was proposed at least a decade prior</li><li>the ASMR format gradually emerged in the 2010s and is also found among the otaku/vtuber community prior to the establishment of the vtuber industry</li><li>Gamergate occured in 2014 and shaped the landscape of social media &amp; culture across the internet</li><li>mid-late 2010s introduces virtual youtubers and therefore gives passage to youtube outpacing nico nico douga and the new &#39;vtuber agency&#39; model emerges</li></ul>",21))])}const w=o(h,[["render",m]]);export{k as __pageData,w as default};
